  1	import * as React from 'react';
  2	import { ErrorHandler } from '@odf/core/components/create-storage-system/error-handler';
  3	import {
  4	  checkError,
  5	  createDownloadFile,
  6	  getIPFamily,
  7	  isValidJSON,
  8	  prettifyJSON,
  9	} from '@odf/core/components/utils';
 10	import { IPFamily } from '@odf/core/constants';
 11	import { useODFNamespaceSelector } from '@odf/core/redux';
 12	import { RHCSState } from '@odf/core/types';
 13	import {
 14	  CanGoToNextStep,
 15	  CreatePayload,
 16	  StorageClassComponentProps as ExternalComponentProps,
 17	  StorageClassWizardStepExtensionProps as ExternalStorage,
 18	} from '@odf/odf-plugin-sdk/extensions';
 19	import { OCS_OPERATOR } from '@odf/shared/constants';
 20	import { useK8sGet } from '@odf/shared/hooks/k8s-get-hook';
 21	import { useFetchCsv } from '@odf/shared/hooks/use-fetch-csv';
 22	import {
 23	  ConfigMapModel,
 24	  PodModel,
 25	  SecretModel,
 26	  StorageClusterModel,
 27	} from '@odf/shared/models';
 28	import { getAnnotations } from '@odf/shared/selectors';
 29	import { ConfigMapKind, ListKind, PodKind } from '@odf/shared/types';
 30	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 31	import { getAPIVersionForModel } from '@odf/shared/utils';
 32	import * as _ from 'lodash-es';
 33	import { Trans } from 'react-i18next';
 34	import {
 35	  FormGroup,
 36	  FileUpload,
 37	  FileUploadProps,
 38	  Form,
 39	  FormHelperText,
 40	  HelperText,
 41	  HelperTextItem,
 42	} from '@patternfly/react-core';
 43	import './system-connection-details.scss';
 44	
 45	const SCRIPT_NAME = 'ceph-external-cluster-details-exporter.py';
 46	
 47	export const getValidationKeys = (
 48	  rawKeys: string
 49	): { plainKeys: string[]; secretKeys: [] } => {
 50	  const { configMaps, secrets, storageClasses } = rawKeys
 51	    ? JSON.parse(rawKeys)
 52	    : { configMaps: [], secrets: [], storageClasses: [] };
 53	  const plainKeys = _.concat(configMaps, storageClasses);
 54	  return { plainKeys, secretKeys: secrets };
 55	};
 56	
 57	const ROOK_EXTERNAL_SCRIPT_CM = 'rook-ceph-external-cluster-script-config';
 58	
 59	export const ConnectionDetails: React.FC<ExternalComponentProps<RHCSState>> = ({
 60	  setFormState,
 61	  formState,
 62	}) => {
 63	  const { t } = useCustomTranslation();
 64	
 65	  const { odfNamespace, isNsSafe, isODFNsLoaded, odfNsLoadError } =
 66	    useODFNamespaceSelector();
 67	
 68	  const [pods, podsLoaded, podsLoadError] =
 69	    useK8sGet<ListKind<PodKind>>(PodModel);
 70	
 71	  const [ocsCSV, ocsCSVLoaded, ocsCSVError] = useFetchCsv({
 72	    specName: OCS_OPERATOR,
 73	    namespace: odfNamespace,
 74	    startPollingInstantly: isNsSafe,
 75	  });
 76	
 77	  const [cm, cmLoaded, cmLoadError] = useK8sGet<ConfigMapKind>(
 78	    ConfigMapModel,
 79	    ROOK_EXTERNAL_SCRIPT_CM,
 80	    odfNamespace
 81	  );
 82	
 83	  const { fileName, fileData, errorMessage, isLoading } = formState;
 84	
 85	  const downloadFile = createDownloadFile(cm?.data?.script);
 86	  const ocsAnnotations = getAnnotations(ocsCSV, {});
 87	
 88	  const handleDataChange: FileUploadProps['onDataChange'] = (
 89	    _event,
 90	    fData: string
 91	  ) => {
 92	    if (isValidJSON(fData)) {
 93	      const { plainKeys, secretKeys } = getValidationKeys(
 94	        ocsAnnotations?.['external.features.ocs.openshift.io/validation']
 95	      );
 96	      const ipAddress: string = pods.items?.[0]?.status?.podIP;
 97	      const ipFamily: IPFamily = ipAddress
 98	        ? getIPFamily(ipAddress)
 99	        : IPFamily.IPV4;
100	      const error: string = checkError(fData, plainKeys, secretKeys, ipFamily);
101	      setFormState('errorMessage', error);
102	    } else {
103	      const invalidString: string = t(
104	        'The uploaded file is not a valid JSON file'
105	      );
106	      setFormState('errorMessage', fData ? invalidString : '');
107	    }
108	    setFormState('fileData', fData);
109	  };
110	
111	  const handleFileChange: FileUploadProps['onFileInputChange'] = (
112	    _event,
113	    file: File
114	  ) => {
115	    const fName = file.name;
116	    setFormState('fileName', fName);
117	  };
118	
119	  return (
120	    <ErrorHandler
121	      error={odfNsLoadError || podsLoadError || ocsCSVError || cmLoadError}
122	      loaded={isODFNsLoaded && podsLoaded && ocsCSVLoaded && cmLoaded}
123	    >
124	      <Form>
125	        <FormGroup
126	          label={t('External storage system metadata')}
127	          fieldId="external-storage-system-metadata"
128	          className="odf-connection-details__form-group"
129	        >
130	          <FormHelperText>
131	            <HelperText>
132	              <HelperTextItem>
133	                <div className="odf-connection-details__helper-text">
134	                  <Trans t={t as any} ns="plugin__odf-console">
135	                    1. Download <code>{{ SCRIPT_NAME }}</code> script and run on
136	                    the RHCS cluster, then upload the results (JSON) in the
137	                    External storage system metadata field.
138	                  </Trans>{' '}
139	                  {!!downloadFile && (
140	                    <a
141	                      id="downloadAnchorElem"
142	                      href={downloadFile}
143	                      download="ceph-external-cluster-details-exporter.py"
144	                      target="_blank"
145	                      rel="noopener noreferrer"
146	                    >
147	                      {t('Download script')}
148	                    </a>
149	                  )}
150	                </div>
151	              </HelperTextItem>
152	              {errorMessage && (
153	                <HelperTextItem variant="error">{errorMessage}</HelperTextItem>
154	              )}
155	            </HelperText>
156	          </FormHelperText>
157	          <FileUpload
158	            id="external-storage-system-metadata"
159	            className="odf-connection-details__file-upload"
160	            type="text"
161	            isRequired
162	            isReadOnly
163	            value={prettifyJSON(fileData ?? '')}
164	            filename={fileName}
165	            isLoading={isLoading}
166	            validated={errorMessage ? 'error' : 'default'}
167	            dropzoneProps={{
168	              accept: { 'text/json': ['.json'] },
169	            }}
170	            onFileInputChange={handleFileChange}
171	            onDataChange={handleDataChange}
172	            onReadStarted={() => setFormState('isLoading', true)}
173	            onReadFinished={() => setFormState('isLoading', false)}
174	            browseButtonText={t('Browse')}
175	            clearButtonText={t('Clear')}
176	            filenamePlaceholder={t('Upload helper script')}
177	          />
178	        </FormGroup>
179	      </Form>
180	    </ErrorHandler>
181	  );
182	};
183	
184	export const rhcsPayload: CreatePayload<RHCSState> = ({
185	  systemName,
186	  state,
187	  namespace,
188	  inTransitStatus,
189	  shouldSetCephRBDAsDefault,
190	  isDbBackup,
191	  dbBackup,
192	}) => {
193	  const storageClusterSpec: Record<string, unknown> = {
194	    network: {
195	      connections: {
196	        encryption: {
197	          enabled: inTransitStatus,
198	        },
199	      },
200	    },
201	    externalStorage: {
202	      enable: true,
203	    },
204	    managedResources: {
205	      cephBlockPools: { defaultStorageClass: shouldSetCephRBDAsDefault },
206	    },
207	    labelSelector: {
208	      matchExpressions: [],
209	    },
210	  };
211	
212	  // Add automatic backup configuration if enabled
213	  if (isDbBackup) {
214	    storageClusterSpec.multiCloudGateway = {
215	      dbBackup: {
216	        schedule: dbBackup.schedule,
217	        volumeSnapshot: dbBackup.volumeSnapshot,
218	      },
219	    };
220	  }
221	
222	  return [
223	    {
224	      model: SecretModel,
225	      payload: {
226	        apiVersion: SecretModel.apiVersion,
227	        kind: SecretModel.kind,
228	        metadata: {
229	          name: 'rook-ceph-external-cluster-details',
230	          namespace: namespace,
231	        },
232	        stringData: {
233	          external_cluster_details: state.fileData,
234	        },
235	        type: 'Opaque',
236	      },
237	    },
238	    {
239	      model: StorageClusterModel,
240	      payload: {
241	        apiVersion: getAPIVersionForModel(StorageClusterModel),
242	        apiGroup: StorageClusterModel.apiGroup,
243	        kind: StorageClusterModel.kind,
244	        metadata: {
245	          name: systemName,
246	          namespace: namespace,
247	        },
248	        spec: storageClusterSpec,
249	      },
250	    },
251	  ];
252	};
253	
254	export const rhcsCanGoToNextStep: CanGoToNextStep<RHCSState> = (state) =>
255	  !!state.fileName &&
256	  !!state.fileData &&
257	  !state.errorMessage &&
258	  !state.isLoading;
259	
260	export const EXTERNAL_CEPH_STORAGE: ExternalStorage[] = [
261	  {
262	    displayName: 'Red Hat Ceph Storage',
263	    model: {
264	      apiGroup: StorageClusterModel.apiGroup,
265	      apiVersion: StorageClusterModel.apiVersion,
266	      kind: StorageClusterModel.kind,
267	      plural: StorageClusterModel.plural,
268	    },
269	    component: ConnectionDetails,
270	    createPayload: rhcsPayload,
271	    canGoToNextStep: rhcsCanGoToNextStep,
272	  },
273	];

